// .NET usa Red-Black Tree internamente no SortedSet<T>
var set = new SortedSet<int>();
set.Add(10); set.Add(5); set.Add(20);
// Acesso O(log n) garantido — a RB tree balanceia automaticamente.
Console.WriteLine(set.Min); // 5
Console.WriteLine(set.Max); // 20

